colacion.`año`,
colacion.nombre_colacion,
colacion.`fecha_colación`,
colacion.fecha_consejo_uni,
colacion.fecha_firma_consejo,
colacion.fecha_resolucion,
colacion.numero_oficio,
autoridades.Autoridad_1,
autoridades.Cargo_auto1,
autoridades.Autoridad_2,
autoridades.Cargo_auto2,
autoridades.Autoridad_3,
autoridades.Cargo_auto3,
informe.number_informe,
informe.id_informe
FROM
expediente
INNER JOIN escuela_profesional ON expediente.Id_escuela = escuela_profesional.Id_escuela
INNER JOIN estudiante ON expediente.Dni = estudiante.Dni
INNER JOIN cede ON expediente.Id_cede = cede.Id_cede
INNER JOIN facultad ON escuela_profesional.Id_facultad = facultad.Cod_facultad
INNER JOIN modalidad ON expediente.Id_expediente = modalidad.Id_expediente
INNER JOIN diploma ON modalidad.Id_modalidad = diploma.id_modalidad
INNER JOIN colacion ON diploma.id_colacion = colacion.id_colacion
INNER JOIN autoridades ON expediente.id_autoridad = autoridades.Cod_autoridad INNER JOIN informe
ON informe.id_informe=expediente.id_informe

WHERE
estudiante.Dni=NRODOC AND escuela_profesional.Grado_academico = 'BACHILLER'
ORDER BY
diploma.estado ASC,
diploma.updated_at DESC$$

CREATE PROCEDURE `SP_CARGAR_NUMERITO` ()   SELECT MAX(id_informe) AS ultimo_id,
       (MAX(number_informe) + 1) AS siguiente_number_informe
FROM informe$$

CREATE PROCEDURE `SP_CARGAR_NUMERITO_POS` ()   SELECT
informe_posgrado.id_informe,
informe_posgrado.number_informe
FROM
informe_posgrado$$

CREATE PROCEDURE `SP_CARGAR_NUMERO_GENERAL` ()   SELECT 
    MAX(diploma.Resolucion_numero) + 1 AS Resolucion,
    MAX(diploma.Diploma_numero) + 1 AS diploma,
    MAX(diploma.Registro_numero) + 1 AS registro,
    MAX(diploma.Registro_libro) AS libro,
    MAX(diploma.Registro_folio) AS folio,
    escuela_profesional.Grado_academico
FROM 
    diploma 
INNER JOIN 
    modalidad ON diploma.id_modalidad = modalidad.Id_modalidad 
INNER JOIN 
    expediente ON modalidad.Id_expediente = expediente.Id_expediente 
INNER JOIN 
    escuela_profesional ON expediente.Id_escuela = escuela_profesional.Id_escuela
WHERE 
    diploma.Diploma_numero > 100
    AND diploma.updated_at = (
        SELECT 
            MAX(d.updated_at) 
        FROM 
            diploma d
        INNER JOIN 
            modalidad m ON d.id_modalidad = m.Id_modalidad
        INNER JOIN 
            expediente e ON m.Id_expediente = e.Id_expediente
        INNER JOIN 
            escuela_profesional ep ON e.Id_escuela = ep.Id_escuela
        WHERE 
            d.Diploma_numero > 100
            AND ep.Grado_academico = 'BACHILLER'
    )
    AND escuela_profesional.Grado_academico = 'BACHILLER'$$

CREATE PROCEDURE `SP_CARGAR_NUMERO_GENERAL_POS` ()   SELECT 
    MAX(diploma_posgrado.Resolucion_numero) + 1 AS Resolucion,
    MAX(diploma_posgrado.Diploma_numero) + 1 AS diploma,
    MAX(diploma_posgrado.Registro_numero) + 1 AS registro,
    MAX(diploma_posgrado.Registro_libro) AS libro,
    MAX(diploma_posgrado.Registro_folio) AS folio
FROM 
    diploma_posgrado
WHERE 
    diploma_posgrado.updated_at = (
        SELECT MAX(diploma_posgrado.updated_at) 
        FROM diploma_posgrado
				WHERE NOT diploma_posgrado.Diploma_numero=0
    )$$

CREATE PROCEDURE `SP_CARGAR_NUMERO_GENERAL_TITULO` ()   SELECT 
    MAX(diploma.Resolucion_numero) + 1 AS Resolucion,
    MAX(diploma.Diploma_numero) + 1 AS diploma,
    MAX(diploma.Registro_numero) + 1 AS registro,
    MAX(diploma.Registro_libro) AS libro,
    MAX(diploma.Registro_folio) AS folio,
    escuela_profesional.Grado_academico
FROM 
    diploma 
INNER JOIN 
    modalidad ON diploma.id_modalidad = modalidad.Id_modalidad 
INNER JOIN 
    expediente ON modalidad.Id_expediente = expediente.Id_expediente 
INNER JOIN 
    escuela_profesional ON expediente.Id_escuela = escuela_profesional.Id_escuela
WHERE 
    diploma.Diploma_numero NOT IN (0, 1) 
    AND diploma.updated_at = (
        SELECT 
            MAX(d.updated_at) 
        FROM 
            diploma d
        INNER JOIN 
            modalidad m ON d.id_modalidad = m.Id_modalidad
        INNER JOIN 
            expediente e ON m.Id_expediente = e.Id_expediente
        INNER JOIN 
            escuela_profesional ep ON e.Id_escuela = ep.Id_escuela
        WHERE 
            d.Diploma_numero NOT IN (0, 1)
            AND ep.Grado_academico = 'TITULO'
    )
    AND escuela_profesional.Grado_academico = 'TITULO'$$

CREATE PROCEDURE `SP_CARGAR_SEGUIMIENTO_GRADUADO` (IN `DNI` CHAR(20))   SELECT
estudiante.Dni, 
