		DATE_FORMAT(cp.fecha_colación, '%d') AS dia,
        CASE MONTH(cp.fecha_colación)
            WHEN 1 THEN 'enero'
            WHEN 2 THEN 'febrero'
            WHEN 3 THEN 'marzo'
