CREATE PROCEDURE `SP_LISTA_GENERAL_INFORMES_AUDITORIA` ()   BEGIN
    SELECT
        id_informe,
        number_informe,
        informe.grado_academico,
        facultad.Cod_facultad,
        facultad.Nombre AS facu,
        id_carrera,
        escuela_profesional.Nombre AS carrera,
        año,
        fecha_desde,
        DATE_FORMAT(fecha_desde, "%d-%m-%Y - %H:%i:%s") AS fecha_formateada1,
        fecha_hasta,
        DATE_FORMAT(fecha_hasta, "%d-%m-%Y - %H:%i:%s") AS fecha_formateada2,
        archivo,
        created
    FROM informe
    INNER JOIN escuela_profesional
        ON informe.id_carrera = escuela_profesional.Id_escuela
    INNER JOIN facultad
        ON escuela_profesional.Id_facultad = facultad.Cod_facultad
    ORDER BY id_informe DESC;
END$$

CREATE PROCEDURE `SP_LISTA_GENERAL_INFORMES_AUDITORIA_FECHAS` (IN `FECHAINICIO` DATE, IN `FECHATERMINO` DATE)   BEGIN
    SELECT
        id_informe,
        number_informe,
        informe.grado_academico,
        facultad.Cod_facultad,
        facultad.Nombre AS facu,
        id_carrera,
        escuela_profesional.Nombre AS carrera,
        año,
        fecha_desde,
        DATE_FORMAT(fecha_desde, "%d-%m-%Y - %H:%i:%s") AS fecha_formateada1,
        fecha_hasta,
        DATE_FORMAT(fecha_hasta, "%d-%m-%Y - %H:%i:%s") AS fecha_formateada2,
        archivo,
        created
    FROM informe
    INNER JOIN escuela_profesional
        ON informe.id_carrera = escuela_profesional.Id_escuela
    INNER JOIN facultad
        ON escuela_profesional.id_facultad = facultad.Cod_facultad
    WHERE created BETWEEN FECHAINICIO AND FECHATERMINO
    ORDER BY id_informe DESC;
END$$

