diploma.Fecha_finalizacion_tramite,
diploma.`años_trans`,
diploma.mes_trans,
diploma.dia_trand,
CONCAT_WS(' ', diploma.años_trans, ' años', diploma.mes_trans, ' meses y', diploma.dia_trand, ' días') AS tiempotrancurrido,
diploma.Nro_creditos,
diploma.Nro_oficio,
diploma.fecha_secreatria_general,
diploma.id_usuario,
diploma.id_modalidad,
diploma.created_at,
diploma.updated_at,
diploma.estado,
colacion.id_colacion,
colacion.`año`,
colacion.nombre_colacion,
colacion.`fecha_colación`,
colacion.fecha_consejo_uni,
colacion.fecha_firma_consejo,
colacion.fecha_resolucion,
colacion.numero_oficio,
autoridades.Autoridad_1,
autoridades.Cargo_auto1,
autoridades.Autoridad_2,
autoridades.Cargo_auto2,
autoridades.Autoridad_3,
autoridades.Cargo_auto3,
informe.number_informe,
informe.id_informe
FROM
expediente
INNER JOIN escuela_profesional ON expediente.Id_escuela = escuela_profesional.Id_escuela
INNER JOIN estudiante ON expediente.Dni = estudiante.Dni
INNER JOIN cede ON expediente.Id_cede = cede.Id_cede
INNER JOIN facultad ON escuela_profesional.Id_facultad = facultad.Cod_facultad
INNER JOIN modalidad ON expediente.Id_expediente = modalidad.Id_expediente
INNER JOIN diploma ON modalidad.Id_modalidad = diploma.id_modalidad
INNER JOIN colacion ON diploma.id_colacion = colacion.id_colacion
INNER JOIN autoridades ON expediente.id_autoridad = autoridades.Cod_autoridad INNER JOIN informe
ON informe.id_informe=expediente.id_informe

WHERE
	escuela_profesional.Grado_academico = 'TITULO' AND expediente.Id_cede=SED
ORDER BY
	diploma.estado ASC,
	diploma.updated_at DESC;
END$$

CREATE PROCEDURE `SP_MODIFICAR_AREA` (IN `ID` INT, IN `NAREA` VARCHAR(255), IN `ESTADO` VARCHAR(20))   BEGIN
DECLARE AREAACTUAL VARCHAR(255);
DECLARE CANTIDAD INT;
SET @AREAACTUAL:=(SELECT area_nombre FROM area WHERE area_cod=ID);
IF @AREAACTUAL = NAREA THEN
	UPDATE area SET
	area_estado=ESTADO,
	area_nombre=NAREA
	WHERE area_cod=ID;
	SELECT 1;
ELSE
SET @CANTIDAD:=(SELECT COUNT(*) FROM area WHERE area_nombre=NAREA);
	IF @CANTIDAD=0 THEN
		UPDATE area SET
		area_estado=ESTADO,
		area_nombre=NAREA
		WHERE area_cod=ID;
		SELECT 1;	
	ELSE
		SELECT 2;	
	END IF;
END IF;
END$$

CREATE PROCEDURE `SP_MODIFICAR_AUTORIDAD` (IN `ID` INT, IN `AUTO1` VARCHAR(100), IN `CARGO1` VARCHAR(100), IN `GEN1` VARCHAR(20), IN `AUTO2` VARCHAR(100), IN `CARGO2` VARCHAR(100), IN `GEN2` VARCHAR(20), IN `AUTO3` VARCHAR(100), IN `CARGO3` VARCHAR(100), IN `GEN3` VARCHAR(20), IN `ESTADO` VARCHAR(20))   BEGIN
DECLARE CANTIDAD INT;
SET @CANTIDAD:=(SELECT COUNT(*) FROM autoridades WHERE Autoridad_1=AUTO1 AND Autoridad_2=AUTO2 AND Autoridad_3=AUTO3 AND estado='ACTIVO');
IF @CANTIDAD=0 THEN
	UPDATE autoridades SET
	Autoridad_1=AUTO1,
	Cargo_auto1=CARGO1,
  genero1=GEN1,
	Autoridad_2=AUTO2,
	Cargo_auto2=CARGO2,
  genero2=GEN2,
	Autoridad_3=AUTO3,
	Cargo_auto3=CARGO3,
  genero3=GEN3,
	updated_at=NOW(),
	estado=ESTADO
	WHERE Cod_autoridad=ID;
	SELECT 1;
ELSE
SELECT 2;

END IF;

END$$

CREATE PROCEDURE `SP_MODIFICAR_BACHILLER` (IN `NDOCUMENTO` CHAR(20), IN `NOMBRE` VARCHAR(150), IN `APEPAT` VARCHAR(100), IN `APEMAT` VARCHAR(100), IN `CODIGO` CHAR(15), IN `SEXO` VARCHAR(20), IN `MOVIL` CHAR(9), IN `DIRECCION` VARCHAR(255), IN `EMAPER` VARCHAR(255), IN `EMAINSTI` VARCHAR(255), IN `FECHAMATRI` DATE, IN `FECHAEGRE` DATE, IN `OBERSER` VARCHAR(255), IN `IDEXPE` CHAR(12), IN `CED` INT, IN `IDESCUE` INT, IN `BACH` VARCHAR(255), IN `MODA` VARCHAR(255), IN `IDAUTO` INT, IN `FECHA` DATETIME, IN `ACUER` VARCHAR(255), IN `RESOL` VARCHAR(255), IN `EXPE` VARCHAR(255), IN `LIB` VARCHAR(255), IN `FOLI` VARCHAR(255), IN `REGIS` VARCHAR(255), IN `RUTA` VARCHAR(255), IN `IDMODA` INT, IN `MODO_ESTU` VARCHAR(100), IN `TRABA_INV` VARCHAR(255), IN `TURNITIN` VARCHAR(20), IN `PORCENTAJE` CHAR(3), IN `CENTRO_INVE` VARCHAR(255), IN `REGLA_META` TEXT, IN `PRO_BACH` VARCHAR(255), IN `PRO_INST` VARCHAR(255), IN `PRO_TITU` VARCHAR(255), IN `FECHA_MATRI_MOD` DATE, IN `FECHA_INIC_MOD` DATE, IN `FECHA_FIN_MOD` DATE, IN `MODO_SUSTE` VARCHAR(20), IN `IDDIPLO` INT, IN `FECHACU` DATE, IN `FECHAFIRMA` DATE, IN `RESOLDIPLO` VARCHAR(30), IN `FECHARESO` DATE, IN `NUMDIPLO` INT, IN `REGINUM` INT, IN `REGISLIB` INT, IN `REGISFOL` CHAR(8), IN `TIPODIPLO` CHAR(1), IN `FECHA_INI_TRA` DATE, IN `NROCREDI` INT, IN `NROOFICIO` VARCHAR(255), IN `FECHASECRE` DATE, IN `USU` INT)   BEGIN
  DECLARE AÑO INT;
  DECLARE MES INT;
  DECLARE DIA INT;

  DECLARE AÑODIPLO INT;
  DECLARE MESDIPLO INT;
  DECLARE DIADIPLO INT;

  DECLARE NDOCUMENTOACTUAL INT;
  DECLARE verificar INT;

  SET @AÑO := (TIMESTAMPDIFF(YEAR, FECHAMATRI, FECHAEGRE));
  SET @MES := (TIMESTAMPDIFF(MONTH, FECHAMATRI, FECHAEGRE) % 12);
  SET @DIA := (FLOOR(TIMESTAMPDIFF(DAY, FECHAMATRI, FECHAEGRE) % 30.4375));

  SET @AÑODIPLO := (TIMESTAMPDIFF(YEAR, FECHA_INI_TRA, NOW()));
  SET @MESDIPLO := (TIMESTAMPDIFF(MONTH, FECHA_INI_TRA, NOW()) % 12);
  SET @DIADIPLO := (FLOOR(TIMESTAMPDIFF(DAY, FECHA_INI_TRA, NOW()) % 30.4375));

  SET @NDOCUMENTOACTUAL := (SELECT Dni FROM estudiante WHERE Dni = NDOCUMENTO);

  -- Verificar duplicados antes de proceder con la actualización
  -- Primer conteo para verificar si existen otros diplomas duplicados
SET @verificar := (
  SELECT COUNT(*) 
  FROM diploma d
  INNER JOIN modalidad m ON d.id_modalidad = m.Id_modalidad
  INNER JOIN expediente e ON m.Id_expediente = e.Id_expediente
  INNER JOIN escuela_profesional ep ON e.Id_escuela = ep.Id_escuela
  WHERE ep.Grado_academico = 'BACHILLER'
    AND (
        d.Resolucion_numero = RESOLDIPLO
        OR d.Diploma_numero = NUMDIPLO
        OR (d.Registro_numero = REGINUM AND Id_Diploma != IDDIPLO)
    )
);

-- Validación de condiciones de coincidencia para evitar operaciones con duplicados
IF @verificar > 0 THEN
  SET @verificar := (
    SELECT COUNT(*) 
    FROM diploma d
    INNER JOIN modalidad m ON d.id_modalidad = m.Id_modalidad
    INNER JOIN expediente e ON m.Id_expediente = e.Id_expediente
    INNER JOIN escuela_profesional ep ON e.Id_escuela = ep.Id_escuela
    WHERE ep.Grado_academico = 'BACHILLER'
      AND d.Resolucion_numero = RESOLDIPLO
      AND d.Diploma_numero = NUMDIPLO
      AND d.Registro_numero = REGINUM
      AND Id_Diploma = IDDIPLO
  );
   IF @verificar = 0 THEN
      SELECT 2;
    END IF;
  END IF;


  IF @NDOCUMENTOACTUAL = NDOCUMENTO THEN
    UPDATE estudiante
    SET	
      Dni = NDOCUMENTO,
      Codigo = CODIGO,
      Nombres = NOMBRE,
      Apellido_paterno = APEPAT,
      Apellido_materno = APEMAT,
      Sexo = SEXO,
      Celular = MOVIL,
      Direccion = DIRECCION,
      Fecha_matricula = FECHAMATRI,
      Fecha_egreso = FECHAEGRE,
      correo_personal = EMAPER,
      correo_institucional = EMAINSTI,
      Observaciones = OBERSER,
      Años_transcurridos = @AÑO,
      Meses_transcurridos = @MES,
      Dias_transcurridos = @DIA,
      id_usuario = USU,
      updated_at = CURDATE()
    WHERE Dni = NDOCUMENTO;

  UPDATE expediente 
    SET
      Id_escuela = IDESCUE,
      Grado_bachiller_de = BACH,
      Modalidad = MODA,
      Acto_academico = '',
      Acuerdo = ACUER,
      Resolucion_rectoral_N = RESOL,
      Expedicion = EXPE,
      Libro = LIB,
      Folio = FOLI,
      Registro = REGIS,
      Archivo = RUTA,
      Id_usuario = USU,
			id_autoridad=IDAUTO,
      estado = 'PROCESO',
      id_usuario = USU,
       created_at = FECHA,
      updated_at = FECHA
    WHERE Id_expediente = IDEXPE;

		IF  MODA = 'BACHILLER AUTOMATICO' THEN


    UPDATE modalidad 
    SET
      Modo_obtencion = MODA,
      Abreviatura_modo_estudio = 'P',
      Modo_estudio = MODO_ESTU,
      Trabajo_investigacion = TRABA_INV,
      Turnitin = TURNITIN,
      Porcentaje = PORCENTAJE,
      Centro_investigacion = CENTRO_INVE,
      Reglamento_metadado = REGLA_META,
      Proce_bachiller = PRO_BACH,
      Proce_insti_origen = PRO_INST,
      Proce_titulo_peda = PRO_TITU,
      Fecha_matricula_modalidad = FECHA_MATRI_MOD,
      Fecha_inicio_modalidad = FECHA_INIC_MOD,
      Fecha_fin_modalidad = FECHA_FIN_MOD,
      Modo_sustentacion = MODO_SUSTE,
      Id_usuario = USU,
      updated_at = CURDATE(),
			lleno=0
    WHERE Id_modalidad = IDMODA;

	ELSE
UPDATE modalidad 
    SET
      Modo_obtencion = MODA,
      Abreviatura_modo_estudio = 'P',
      Modo_estudio = MODO_ESTU,
      Trabajo_investigacion = TRABA_INV,
      Turnitin = TURNITIN,
      Porcentaje = PORCENTAJE,
      Centro_investigacion = CENTRO_INVE,
      Reglamento_metadado = REGLA_META,
      Proce_bachiller = PRO_BACH,
      Proce_insti_origen = PRO_INST,
      Proce_titulo_peda = PRO_TITU,
      Fecha_matricula_modalidad = FECHA_MATRI_MOD,
      Fecha_inicio_modalidad = FECHA_INIC_MOD,
      Fecha_fin_modalidad = FECHA_FIN_MOD,
      Modo_sustentacion = MODO_SUSTE,
      Id_usuario = USU,
      updated_at = CURDATE(),
			lleno=1
    WHERE Id_modalidad = IDMODA;

END IF;

    UPDATE diploma 
    SET
		  fecha_consejo_uni=FECHACU,
			fecha_firma=FECHAFIRMA,
      Resolucion_numero = RESOLDIPLO,
			fecha_resolucion=FECHARESO,
      Diploma_numero = NUMDIPLO,
      Registro_numero = REGINUM,
      Registro_libro = REGISLIB,
      Registro_folio = REGISFOL,
      Diploma_tipo_emitido = TIPODIPLO,
      Fecha_inicio_tramite = FECHA_INI_TRA,
      Fecha_finalizacion_tramite = CURDATE(),
      años_trans = @AÑODIPLO,
      mes_trans = @MESDIPLO,
      dia_trand = @DIADIPLO,
      Nro_creditos = NROCREDI,
      Nro_oficio = NROOFICIO,
			fecha_secreatria_general=FECHASECRE,
      id_usuario = USU,
      updated_at = CURDATE()
    WHERE Id_Diploma = IDDIPLO;

    SELECT 1;
  ELSE
    SELECT 2;
  END IF;
END$$

CREATE PROCEDURE `SP_MODIFICAR_CARRERA` (IN `ID` INT, IN `ESCUE` CHAR(11), IN `NOMBRES` VARCHAR(100), IN `GRADOACA` VARCHAR(100), IN `ABRE` CHAR(2), IN `DENOMI` VARCHAR(100), IN `PROGRAMA` VARCHAR(100), IN `CRED` INT, IN `FACUL` INT, IN `ESTADO` VARCHAR(20))   BEGIN
DECLARE DENO VARCHAR(20);
DECLARE CANTIDAD INT;
SET @DENO:=(SELECT escuela_profesional.`Denominación_grado` FROM escuela_profesional WHERE Id_escuela=ID);
IF @DENO = DENOMI THEN
	UPDATE escuela_profesional SET
	Cod_Escuela=ESCUE,
	Nombre=NOMBRES,
	Grado_academico=GRADOACA,
	Abreviatura_grado=ABRE,
	Denominación_grado=DENOMI,
	Programa_estudio=PROGRAMA,
	Numero_creditos=CRED,
	Id_facultad=FACUL,
	updated_at=NOW(),
	estado=ESTADO
	WHERE Id_escuela=ID;
	SELECT 1;
ELSE
SET @CANTIDAD:=(SELECT COUNT(*) FROM escuela_profesional WHERE Nombre=NOMBRES AND Grado_academico=GRADOACA AND `Denominación_grado`=DENOMI);
IF @CANTIDAD=0 THEN
	UPDATE escuela_profesional SET
		Cod_Escuela=ESCUE,
	Nombre=NOMBRES,
	Grado_academico=GRADOACA,
	Abreviatura_grado=ABRE,
	Denominación_grado=DENOMI,
	Programa_estudio=PROGRAMA,
	Numero_creditos=CRED,
	Id_facultad=FACUL,
	updated_at=NOW(),
	estado=ESTADO
	WHERE Id_escuela=ID;
	SELECT 1;
ELSE
SELECT 2;

END IF;

END IF;

END$$

CREATE PROCEDURE `SP_MODIFICAR_CEDE` (IN `ID` INT, IN `CED` VARCHAR(255), IN `DESCRIP` VARCHAR(255), IN `ESTA` VARCHAR(100))   BEGIN
DECLARE CEDACTUAL CHAR(12);
DECLARE CANTIDAD INT;
