IF @CANTIDAD=0 THEN
UPDATE cede SET
	cede_nombre=CED,
	descripcion=DESCRIP,
	estado=ESTA,
	updated_at=NOW()
	WHERE Id_cede=ID;
	SELECT 1;
ELSE
SELECT 2;

END IF;

END IF;



END$$

CREATE PROCEDURE `SP_MODIFICAR_COLACION` (IN `ID` INT, IN `COLA` VARCHAR(255), IN `FECHACOLA` DATE, IN `FECHACONSEJO` DATE, IN `FECHAFIRMA` DATE, IN `FECHARESOL` DATE, IN `OFICIIO` VARCHAR(255))   BEGIN
DECLARE AÑO INT;
DECLARE FECHA_ACTUAL DATE;
DECLARE CANTIDAD INT;
SET @AÑO:=(SELECT YEAR(NOW()));
SET @FECHA_ACTUAL:=(SELECT colacion.fecha_colación FROM colacion WHERE colacion.id_colacion=ID);
IF @FECHA_ACTUAL = FECHACOLA THEN
	UPDATE colacion SET
	año=@AÑO,
	nombre_colacion=COLA,
	fecha_colación=FECHACOLA,
	fecha_consejo_uni=FECHACONSEJO,
	fecha_firma_consejo=FECHAFIRMA,
	fecha_resolucion=FECHARESOL,
	numero_oficio=OFICIIO,
	updated_at=NOW()
	WHERE id_colacion=ID;
	SELECT 1;
ELSE
SET @CANTIDAD:=(SELECT COUNT(*) FROM colacion WHERE colacion.`fecha_colación`=FECHACOLA);
IF @CANTIDAD=0 THEN
	UPDATE colacion SET
	año=@AÑO,
	nombre_colacion=COLA,
	fecha_colación=FECHACOLA,
	fecha_consejo_uni=FECHACONSEJO,
	fecha_firma_consejo=FECHAFIRMA,
	fecha_resolucion=FECHARESOL,
	numero_oficio=OFICIIO,
	updated_at=NOW()
	WHERE id_colacion=ID;
	SELECT 1;
ELSE
SELECT 2;

END IF;

END IF;



END$$

