CREATE PROCEDURE `SP_MODIFICAR_MODALIDAD_BACHILLER` (IN `ID_MODA` INT, IN `EXPE_ACT` CHAR(12), IN `EXPE` VARCHAR(12), IN `MODO_OB` VARCHAR(150), IN `MODO_ESTU` VARCHAR(100), IN `PRO_BACH` VARCHAR(255), IN `PRO_INST` VARCHAR(255), IN `PRO_TITU` VARCHAR(255), IN `USU` INT)   BEGIN
DECLARE CANTIDAD INT;
IF EXPE_ACT = EXPE THEN
	UPDATE modalidad SET
	Modo_obtencion=MODO_OB,
	Modo_estudio=MODO_ESTU,
	Proce_bachiller=PRO_BACH,
	Proce_insti_origen=PRO_INST,
	Proce_titulo_peda=PRO_TITU,
	Id_usuario=USU,
	Id_expediente=EXPE,
	updated_at=NOW()
	WHERE Id_modalidad=ID_MODA;
	
	SELECT 1;
ELSE
IF EXPE_ACT <> EXPE THEN
	UPDATE modalidad SET
	Modo_obtencion=MODO_OB,
	Modo_estudio=MODO_ESTU,
	Proce_bachiller=PRO_BACH,
	Proce_insti_origen=PRO_INST,
	Proce_titulo_peda=PRO_TITU,
	Id_usuario=USU,
	Id_expediente=EXPE,
	updated_at=NOW()
	WHERE Id_modalidad=ID_MODA;
UPDATE expediente
SET expediente.estado='PENDIENTE'
WHERE expediente.Id_expediente=EXPE_ACT;
UPDATE expediente
SET expediente.estado='EN PROCESO'
WHERE expediente.Id_expediente=EXPE;
	SELECT 1;
ELSE
SELECT 2;

END IF;

END IF;



END$$

