CREATE PROCEDURE `SP_MODIFICAR_POSGRADO` (IN `NDOCUMENTO` CHAR(20), IN `NOMBRE` VARCHAR(150), IN `APEPAT` VARCHAR(100), IN `APEMAT` VARCHAR(100), IN `CODIGO` CHAR(15), IN `SEXO` VARCHAR(20), IN `MOVIL` CHAR(9), IN `DIRECCION` VARCHAR(255), IN `EMAPER` VARCHAR(255), IN `EMAINSTI` VARCHAR(255), IN `FECHAMATRI` DATE, IN `FECHAEGRE` DATE, IN `OBERSER` VARCHAR(255), IN `IDEXPE` CHAR(12), IN `IDPROGRA` INT, IN `MAES` VARCHAR(255), IN `MODA` VARCHAR(255), IN `IDAUTO` INT, IN `FECHA` DATE, IN `ACTOACA` VARCHAR(255), IN `ACUER` VARCHAR(255), IN `RESOL` VARCHAR(255), IN `EXPE` VARCHAR(255), IN `LIB` VARCHAR(255), IN `FOLI` VARCHAR(255), IN `REGIS` VARCHAR(255), IN `RUTA` VARCHAR(255), IN `IDMODA` INT, IN `MODO_ESTU` VARCHAR(100), IN `TRABA_INV` VARCHAR(255), IN `TURNITIN` VARCHAR(20), IN `PORCENTAJE` CHAR(3), IN `CENTRO_INVE` VARCHAR(255), IN `REGLA_META` TEXT, IN `PRO_PAIS` VARCHAR(255), IN `PRO_UNI` VARCHAR(255), IN `PRO_GRADO` VARCHAR(255), IN `FECHA_MATRI_MOD` DATE, IN `FECHA_INIC_MOD` DATE, IN `FECHA_FIN_MOD` DATE, IN `MODO_SUSTE` VARCHAR(20), IN `IDDIPLO` INT, IN `FECHACU` DATE, IN `FECHAFIRMA` DATE, IN `RESOLDIPLO` VARCHAR(30), IN `FECHARESO` DATE, IN `NUMDIPLO` INT, IN `REGINUM` INT, IN `REGISLIB` INT, IN `REGISFOL` VARCHAR(100), IN `TIPODIPLO` CHAR(1), IN `FECHA_INI_TRA` DATE, IN `NROCREDI` INT, IN `NROOFICIO` VARCHAR(255), IN `FECHASECRE` DATE, IN `USU` INT)   BEGIN
  DECLARE AÑO INT;
  DECLARE MES INT;
  DECLARE DIA INT;

  DECLARE AÑODIPLO INT;
  DECLARE MESDIPLO INT;
  DECLARE DIADIPLO INT;

  DECLARE NDOCUMENTOACTUAL INT;
  DECLARE verificar INT;

  SET @AÑO := (TIMESTAMPDIFF(YEAR, FECHAMATRI, FECHAEGRE));
  SET @MES := (TIMESTAMPDIFF(MONTH, FECHAMATRI, FECHAEGRE) % 12);
  SET @DIA := (FLOOR(TIMESTAMPDIFF(DAY, FECHAMATRI, FECHAEGRE) % 30.4375));

  SET @AÑODIPLO := (TIMESTAMPDIFF(YEAR, FECHA_INI_TRA, NOW()));
  SET @MESDIPLO := (TIMESTAMPDIFF(MONTH, FECHA_INI_TRA, NOW()) % 12);
  SET @DIADIPLO := (FLOOR(TIMESTAMPDIFF(DAY, FECHA_INI_TRA, NOW()) % 30.4375));

  SET @NDOCUMENTOACTUAL := (SELECT Dni FROM estudiante_posgrado WHERE Dni = NDOCUMENTO);

  -- Verificar duplicados antes de proceder con la actualización
  SET @verificar := (SELECT COUNT(*) FROM diploma_posgrado
                     WHERE (Resolucion_numero = RESOLDIPLO OR Diploma_numero = NUMDIPLO OR Registro_numero = REGINUM AND Id_Diploma != IDDIPLO));

  IF @verificar > 0 THEN
    -- Verificar si los valores actuales coinciden con los nuevos valores
    SET @verificar := (SELECT COUNT(*) FROM diploma_posgrado 
                       WHERE (Resolucion_numero = RESOLDIPLO AND Diploma_numero = NUMDIPLO AND Registro_numero = REGINUM AND Id_Diploma = IDDIPLO));

    IF @verificar = 0 THEN
      SELECT 2;
    END IF;
  END IF;

  IF @NDOCUMENTOACTUAL = NDOCUMENTO THEN
    UPDATE estudiante_posgrado
    SET	
      Dni = NDOCUMENTO,
      Codigo = CODIGO,
      Nombres = NOMBRE,
      Apellido_paterno = APEPAT,
      Apellido_materno = APEMAT,
      Sexo = SEXO,
      Celular = MOVIL,
      Direccion = DIRECCION,
      Fecha_matricula = FECHAMATRI,
      Fecha_egreso = FECHAEGRE,
      correo_personal = EMAPER,
      correo_institucional = EMAINSTI,
      Observaciones = OBERSER,
      Años_transcurridos = @AÑO,
      Meses_transcurridos = @MES,
      Dias_transcurridos = @DIA,
      id_usuario = USU,
      updated_at = CURDATE()
    WHERE Dni = NDOCUMENTO;

    UPDATE expediente_posgrado 
    SET
      Id_programa = IDPROGRA,
      Grado_maestro_de = MAES,
      Modalidad = MODA,
      Acto_academico = ACTOACA,
      Acuerdo = ACUER,
      Resolucion_rectoral_N = RESOL,
      Expedicion = EXPE,
      Libro = LIB,
      Folio = FOLI,
      Registro = REGIS,
      Archivo = RUTA,
      Id_usuario = USU,
      estado = 'EN PROCESO',
      id_usuario = USU,
			id_autoridad=IDAUTO,
      created_at = FECHA,
      updated_at = CURDATE()
    WHERE Id_expediente = IDEXPE;

    UPDATE modalidad_posgrado
    SET
      Modo_obtencion = MODA,
      Abreviatura_modo_estudio = 'P',
      Modo_estudio = MODO_ESTU,
      Trabajo_investigacion = TRABA_INV,
      Turnitin = TURNITIN,
      Porcentaje = PORCENTAJE,
      Centro_investigacion = CENTRO_INVE,
      Reglamento_metadado = REGLA_META,
      Proce_pais_ext = PRO_PAIS,
      Proce_univ_ext = PRO_UNI,
      Proce_grado_ext = PRO_GRADO,
      Fecha_matricula_modalidad = FECHA_MATRI_MOD,
      Fecha_inicio_modalidad = FECHA_INIC_MOD,
      Fecha_fin_modalidad = FECHA_FIN_MOD,
      Modo_sustentacion = MODO_SUSTE,
      Id_usuario = USU,
      updated_at = CURDATE()
    WHERE Id_modalidad = IDMODA;

    UPDATE diploma_posgrado
    SET
		  fecha_consejo_uni=FECHACU,
			fecha_firma=FECHAFIRMA,
      Resolucion_numero = RESOLDIPLO,
			fecha_resolucion=FECHARESO,
      Diploma_numero = NUMDIPLO,
      Registro_numero = REGINUM,
      Registro_libro = REGISLIB,
      Registro_folio = REGISFOL,
      Diploma_tipo_emitido = TIPODIPLO,
      Fecha_inicio_tramite = FECHA_INI_TRA,
      Fecha_finalizacion_tramite = CURDATE(),
      años_trans = @AÑODIPLO,
      mes_trans = @MESDIPLO,
      dia_trand = @DIADIPLO,
      Nro_creditos = NROCREDI,
      Nro_oficio = NROOFICIO,
			fecha_secreatria_general=FECHASECRE,
      id_usuario = USU,
      updated_at = CURDATE()
    WHERE Id_Diploma = IDDIPLO;

    SELECT 1;
  ELSE
    SELECT 2;
  END IF;
END$$

CREATE PROCEDURE `SP_MODIFICAR_PROGRAMA` (IN `ID` INT, IN `NOMBRES` VARCHAR(100), IN `GRADOACA` VARCHAR(100), IN `ABRE` CHAR(2), IN `DENOMI` VARCHAR(100), IN `PROGRAMA` VARCHAR(100), IN `CRED` INT, IN `DIRE` INT, IN `ESTADO` VARCHAR(20))   BEGIN
DECLARE DENO VARCHAR(20);
DECLARE CANTIDAD INT;
SET @DENO:=(SELECT programa_posgrado.`Denominación_grado` FROM programa_posgrado WHERE Id_programa=ID);
IF @DENO = DENOMI THEN
	UPDATE programa_posgrado SET
	Nombre=NOMBRES,
	Grado_academico=GRADOACA,
	Abreviatura_grado=ABRE,
	Denominación_grado=DENOMI,
	Programa_estudio=PROGRAMA,
	Numero_creditos=CRED,
	id_autoridad=DIRE,
	updated_at=NOW(),
	estado=ESTADO
	WHERE Id_programa=ID;
	SELECT 1;
ELSE
SET @CANTIDAD:=(SELECT COUNT(*) FROM programa_posgrado WHERE Nombre=NOMBRES AND `Denominación_grado`=DENOMI);
IF @CANTIDAD=0 THEN
	UPDATE programa_posgrado SET
	Nombre=NOMBRES,
	Grado_academico=GRADOACA,
	Abreviatura_grado=ABRE,
	Denominación_grado=DENOMI,
	Programa_estudio=PROGRAMA,
	Numero_creditos=CRED,
	id_autoridad=DIRE,
	updated_at=NOW(),
	estado=ESTADO
	WHERE Id_programa=ID;
	SELECT 1;
ELSE
SELECT 2;

END IF;

END IF;

END$$

CREATE PROCEDURE `SP_MODIFICAR_TITULADO` (IN `NDOCUMENTO` CHAR(20), IN `NOMBRE` VARCHAR(150), IN `APEPAT` VARCHAR(100), IN `APEMAT` VARCHAR(100), IN `CODIGO` CHAR(15), IN `SEXO` VARCHAR(20), IN `MOVIL` CHAR(9), IN `DIRECCION` VARCHAR(255), IN `EMAPER` VARCHAR(255), IN `EMAINSTI` VARCHAR(255), IN `FECHAMATRI` DATE, IN `FECHAEGRE` DATE, IN `OBERSER` VARCHAR(255), IN `IDEXPE` CHAR(12), IN `CED` INT, IN `IDESCUE` INT, IN `TITU` VARCHAR(255), IN `MODA` VARCHAR(255), IN `ID_AUTO` INT, IN `FECHA` DATETIME, IN `ACTOACA` VARCHAR(255), IN `ACUER` VARCHAR(255), IN `RESOL` VARCHAR(255), IN `EXPE` VARCHAR(255), IN `LIB` VARCHAR(255), IN `FOLI` VARCHAR(255), IN `REGIS` VARCHAR(255), IN `RUTA` VARCHAR(255), IN `IDMODA` INT, IN `MODO_ESTU` VARCHAR(100), IN `TRABA_INV` VARCHAR(255), IN `TURNITIN` VARCHAR(20), IN `PORCENTAJE` CHAR(3), IN `CENTRO_INVE` VARCHAR(255), IN `REGLA_META` TEXT, IN `PRO_BACH` VARCHAR(255), IN `PRO_INST` VARCHAR(255), IN `PRO_TITU` VARCHAR(255), IN `FECHA_MATRI_MOD` DATE, IN `FECHA_INIC_MOD` DATE, IN `FECHA_FIN_MOD` DATE, IN `MODO_SUSTE` VARCHAR(20), IN `IDDIPLO` INT, IN `FECHACU` DATE, IN `FECHAFIRMA` DATE, IN `RESOLDIPLO` VARCHAR(30), IN `FECHARESO` DATE, IN `NUMDIPLO` INT, IN `REGINUM` INT, IN `REGISLIB` INT, IN `REGISFOL` CHAR(8), IN `TIPODIPLO` CHAR(1), IN `FECHA_INI_TRA` DATE, IN `NROCREDI` INT, IN `NROOFICIO` VARCHAR(255), IN `FECHASECRE` DATE, IN `USU` INT)   BEGIN
  DECLARE AÑO INT;
  DECLARE MES INT;
  DECLARE DIA INT;

  DECLARE AÑODIPLO INT;
  DECLARE MESDIPLO INT;
  DECLARE DIADIPLO INT;

  DECLARE NDOCUMENTOACTUAL INT;
  DECLARE verificar INT;

  SET @AÑO := (TIMESTAMPDIFF(YEAR, FECHAMATRI, FECHAEGRE));
  SET @MES := (TIMESTAMPDIFF(MONTH, FECHAMATRI, FECHAEGRE) % 12);
  SET @DIA := (FLOOR(TIMESTAMPDIFF(DAY, FECHAMATRI, FECHAEGRE) % 30.4375));

  SET @AÑODIPLO := (TIMESTAMPDIFF(YEAR, FECHA_INI_TRA, NOW()));
  SET @MESDIPLO := (TIMESTAMPDIFF(MONTH, FECHA_INI_TRA, NOW()) % 12);
  SET @DIADIPLO := (FLOOR(TIMESTAMPDIFF(DAY, FECHA_INI_TRA, NOW()) % 30.4375));

  SET @NDOCUMENTOACTUAL := (SELECT Dni FROM estudiante WHERE Dni = NDOCUMENTO);

  -- Verificar duplicados antes de proceder con la actualización
SET @verificar := (
  SELECT COUNT(*) 
  FROM diploma d
  INNER JOIN modalidad m ON d.id_modalidad = m.Id_modalidad
  INNER JOIN expediente e ON m.Id_expediente = e.Id_expediente
  INNER JOIN escuela_profesional ep ON e.Id_escuela = ep.Id_escuela
  WHERE ep.Grado_academico = 'TITULO'
    AND (
        d.Resolucion_numero = RESOLDIPLO
        OR d.Diploma_numero = NUMDIPLO
        OR (d.Registro_numero = REGINUM AND Id_Diploma != IDDIPLO)
    )
);

-- Validación de condiciones de coincidencia para evitar operaciones con duplicados
IF @verificar > 0 THEN
  SET @verificar := (
    SELECT COUNT(*) 
    FROM diploma d
    INNER JOIN modalidad m ON d.id_modalidad = m.Id_modalidad
    INNER JOIN expediente e ON m.Id_expediente = e.Id_expediente
    INNER JOIN escuela_profesional ep ON e.Id_escuela = ep.Id_escuela
    WHERE ep.Grado_academico = 'TITULO'
      AND d.Resolucion_numero = RESOLDIPLO
      AND d.Diploma_numero = NUMDIPLO
      AND d.Registro_numero = REGINUM
      AND Id_Diploma = IDDIPLO
  );
   IF @verificar = 0 THEN
      SELECT 2;
    END IF;
  END IF;


  IF @NDOCUMENTOACTUAL = NDOCUMENTO THEN
    UPDATE estudiante
    SET	
      Dni = NDOCUMENTO,
      Codigo = CODIGO,
      Nombres = NOMBRE,
      Apellido_paterno = APEPAT,
      Apellido_materno = APEMAT,
      Sexo = SEXO,
      Celular = MOVIL,
      Direccion = DIRECCION,
      Fecha_matricula = FECHAMATRI,
      Fecha_egreso = FECHAEGRE,
      correo_personal = EMAPER,
      correo_institucional = EMAINSTI,
      Observaciones = OBERSER,
      Años_transcurridos = @AÑO,
      Meses_transcurridos = @MES,
      Dias_transcurridos = @DIA,
      id_usuario = USU,
      updated_at = CURDATE()
    WHERE Dni = NDOCUMENTO;

    UPDATE expediente 
    SET
      Id_escuela = IDESCUE,
      Titulo_de = TITU,
      Modalidad = MODA,
      Acto_academico = ACTOACA,
      Acuerdo = ACUER,
      Resolucion_rectoral_N = RESOL,
      Expedicion = EXPE,
      Libro = LIB,
      Folio = FOLI,
      Registro = REGIS,
      Archivo = RUTA,
      Id_usuario = USU,
      estado = 'PROCESO',
      id_usuario = USU,
	  id_autoridad=ID_AUTO,
      created_at = FECHA,
      updated_at = FECHA
    WHERE Id_expediente = IDEXPE;

    UPDATE modalidad 
    SET
      Modo_obtencion = MODA,
      Abreviatura_modo_estudio = 'P',
      Modo_estudio = MODO_ESTU,
      Trabajo_investigacion = TRABA_INV,
      Turnitin = TURNITIN,
      Porcentaje = PORCENTAJE,
      Centro_investigacion = CENTRO_INVE,
      Reglamento_metadado = REGLA_META,
      Proce_bachiller = PRO_BACH,
      Proce_insti_origen = PRO_INST,
      Proce_titulo_peda = PRO_TITU,
      Fecha_matricula_modalidad = FECHA_MATRI_MOD,
      Fecha_inicio_modalidad = FECHA_INIC_MOD,
      Fecha_fin_modalidad = FECHA_FIN_MOD,
      Modo_sustentacion = MODO_SUSTE,
      Id_usuario = USU,
      updated_at = CURDATE()
    WHERE Id_modalidad = IDMODA;

    UPDATE diploma 
    SET
		  fecha_consejo_uni=FECHACU,
			fecha_firma=FECHAFIRMA,
      Resolucion_numero = RESOLDIPLO,
			fecha_resolucion=FECHARESO,
      Diploma_numero = NUMDIPLO,
      Registro_numero = REGINUM,
      Registro_libro = REGISLIB,
      Registro_folio = REGISFOL,
      Diploma_tipo_emitido = TIPODIPLO,
      Fecha_inicio_tramite = FECHA_INI_TRA,
      Fecha_finalizacion_tramite = CURDATE(),
      años_trans = @AÑODIPLO,
      mes_trans = @MESDIPLO,
      dia_trand = @DIADIPLO,
      Nro_creditos = NROCREDI,
      Nro_oficio = NROOFICIO,
			fecha_secreatria_general=FECHASECRE,
      id_usuario = USU,
      updated_at = CURDATE()
    WHERE Id_Diploma = IDDIPLO;

    SELECT 1;
  ELSE
    SELECT 2;
  END IF;
END$$

CREATE PROCEDURE `SP_MODIFICAR_USUARIO` (IN `ID` VARCHAR(255), IN `IDEMPLEADO` INT, IN `IDAREA` INT, IN `ROL` VARCHAR(25), IN `SED` INT)   UPDATE usuario SET
usuario.empleado_id = IDEMPLEADO,
