CREATE PROCEDURE `SP_PASAR_BACHILLER` (IN `IDEXPE` CHAR(12), IN `IDAUTO` INT, IN `IDESCU` INT, IN `GRADO` VARCHAR(255), IN `MODA` VARCHAR(30))   BEGIN
    -- Actualización en la tabla expediente
    UPDATE expediente
    SET
        id_autoridad = IDAUTO,
        Id_escuela = IDESCU,
        Titulo_de = NULL,  -- Usar NULL si quieres dejar el campo vacío
        Grado_bachiller_de = GRADO,
        Modalidad = MODA
    WHERE Id_expediente = IDEXPE;

    -- Actualización en la tabla modalidad
    UPDATE modalidad
    SET
        Modo_obtencion = MODA
    WHERE Id_expediente = IDEXPE;

END$$

CREATE PROCEDURE `SP_PASAR_TITULADO` (IN `IDEXPE` CHAR(12), IN `IDAUTO` INT, IN `IDESCU` INT, IN `GRADO` VARCHAR(255), IN `MODA` VARCHAR(30))   BEGIN
    -- Actualización en la tabla expediente
    UPDATE expediente
    SET
        id_autoridad = IDAUTO,
        Id_escuela = IDESCU,
        Titulo_de = GRADO,
        Grado_bachiller_de = NULL,
        Modalidad = MODA
    WHERE Id_expediente = IDEXPE;

    -- Actualización en la tabla modalidad
    UPDATE modalidad
    SET
        Modo_obtencion = MODA
    WHERE Id_expediente = IDEXPE;

END$$

CREATE PROCEDURE `SP_REGISTRAR_AREA` (IN `NAREA` VARCHAR(255))   BEGIN
DECLARE CANTIDAD INT;
SET @CANTIDAD:=(SELECT COUNT(*) FROM area where area_nombre=NAREA);
IF @CANTIDAD = 0 THEN
SELECT 1;
ELSE
SELECT 2;

END IF;

END$$

CREATE PROCEDURE `SP_REGISTRAR_AUTORIDAD` (IN `AUTO1` VARCHAR(100), IN `CARGO1` VARCHAR(100), IN `GENE1` VARCHAR(20), IN `AUTO2` VARCHAR(100), IN `CARGO2` VARCHAR(100), IN `GENE2` VARCHAR(20), IN `AUTO3` VARCHAR(100), IN `CARGO3` VARCHAR(100), IN `GENE3` VARCHAR(20))   BEGIN
DECLARE CANTIDAD INT;
SET @CANTIDAD:=(SELECT COUNT(*) FROM autoridades WHERE Autoridad_1=AUTO1 AND Autoridad_2=AUTO2 AND Autoridad_3=AUTO3);
IF @CANTIDAD=0 THEN
SELECT 1;
ELSE
SELECT 2;

END IF;

END$$

CREATE PROCEDURE `SP_REGISTRAR_BACHILLER` (IN `TIPODOC` VARCHAR(20), IN `NDOCUMENTO` CHAR(20), IN `NOMBRE` VARCHAR(150), IN `APEPAT` VARCHAR(100), IN `APEMAT` VARCHAR(100), IN `CODIGO` CHAR(15), IN `SEXO` VARCHAR(20), IN `MOVIL` CHAR(9), IN `DIRECCION` VARCHAR(255), IN `EMAPER` VARCHAR(255), IN `EMAINSTI` VARCHAR(255), IN `FECHAMATRI` DATE, IN `FECHAEGRE` DATE, IN `OBERSER` VARCHAR(255), IN `CED` INT, IN `IDESCUE` INT, IN `BACH` VARCHAR(255), IN `MODA` VARCHAR(255), IN `IDAUTO` INT, IN `FECHA` DATETIME, IN `ACUER` VARCHAR(255), IN `RESOL` VARCHAR(255), IN `EXPE` VARCHAR(255), IN `LIB` VARCHAR(255), IN `FOLI` VARCHAR(255), IN `REGIS` VARCHAR(255), IN `RUTA` VARCHAR(255), IN `MODO_ESTU` VARCHAR(100), IN `TRABA_INV` VARCHAR(255), IN `TURNITIN` VARCHAR(20), IN `PORCENTAJE` CHAR(3), IN `CENTRO_INVE` VARCHAR(255), IN `REGLA_META` TEXT, IN `PRO_BACH` VARCHAR(255), IN `PRO_INST` VARCHAR(255), IN `PRO_TITU` VARCHAR(255), IN `FECHA_MATRI_MOD` DATE, IN `FECHA_INIC_MOD` DATE, IN `FECHA_FIN_MOD` DATE, IN `MODO_SUSTE` VARCHAR(20), IN `USU` INT)   BEGIN
DECLARE AÑO INT;
DECLARE MES INT;
DECLARE DIA INT;
DECLARE cantidad INT;
DECLARE cod char(12);
DECLARE verificar INT;
DECLARE conteo INT;
DECLARE ulti int;
DECLARE ULID INT;


SET @AÑO:=(TIMESTAMPDIFF( YEAR, FECHAMATRI, FECHAEGRE));
SET @MES:=(TIMESTAMPDIFF( MONTH, FECHAMATRI, FECHAEGRE) % 12);
SET @DIA:=(FLOOR( TIMESTAMPDIFF( DAY, FECHAMATRI, FECHAEGRE) % 30.4375 ));
SET @cantidad :=(SELECT IFNULL(MAX(doc_ncorrelativo),0) FROM expediente );
IF @cantidad >= 1 AND @cantidad <= 8 THEN
SET @cod :=(SELECT CONCAT('E000000',(@cantidad+1)));
