CREATE PROCEDURE `SP_REGISTRAR_COLACION` (IN `COLA` VARCHAR(255), IN `FECHACOLA` DATE, IN `FECHACONSEJO` DATE, IN `FECHAFIRMA` DATE, IN `FECHARESOL` DATE, IN `OFICIIO` VARCHAR(255))   BEGIN
DECLARE CANTIDAD INT;
DECLARE AÑO INT;
DECLARE ULID INT;
SET @AÑO:=(SELECT YEAR(NOW()));
SET @CANTIDAD:=(SELECT COUNT(*) FROM colacion WHERE colacion.nombre_colacion=COLA and colacion.`fecha_colación`=FECHACOLA);
IF @CANTIDAD=0 THEN
UPDATE colacion
SET estado='PASADO';

SET @ULID:=(SELECT MAX(colacion.id_colacion) FROM colacion);
UPDATE diploma
set diploma.id_colacion=@ULID
where diploma.estado='SIN DIPLOMA';
SELECT 1;
ELSE
SELECT 2;

END IF;




END$$

