CREATE PROCEDURE `SP_REGISTRAR_INFORME` (IN `NUMERO` INT, IN `GRADO` VARCHAR(255), IN `PROGRAMA` INT, IN `FECHADES` DATETIME, IN `FECHAHASTA` DATETIME, IN `RUTA` VARCHAR(255))   BEGIN
    DECLARE ULID INT;
    DECLARE CANTIDAD INT;

    -- Verificar la cantidad de informes existentes para el número y año actual
    SELECT COUNT(*) INTO CANTIDAD 
    FROM informe 
    WHERE informe.id_informe=100000;

    IF CANTIDAD = 0 THEN
        -- Insertar un nuevo registro en la tabla informe
        VALUES (NUMERO, GRADO, PROGRAMA, YEAR(CURDATE()), FECHADES, FECHAHASTA, RUTA, CURDATE());

        -- Obtener el último ID insertado en la tabla informe
        SELECT LAST_INSERT_ID() INTO ULID;

        -- Actualizar los registros en expediente que cumplan con la condición
        UPDATE expediente
        INNER JOIN escuela_profesional ON expediente.Id_escuela = escuela_profesional.Id_escuela
        SET expediente.id_informe = ULID
        WHERE Grado_academico = GRADO 
          AND escuela_profesional.Id_escuela = PROGRAMA 
          AND expediente.created_at BETWEEN FECHADES AND FECHAHASTA;

        -- Retornar 1 para indicar éxito
        SELECT 1;
    ELSE
        -- Retornar 2 para indicar que ya existe un informe para el año actual
        SELECT 2;
    END IF;
END$$

