DELIMITER $$
--
-- Eventos
--
CREATE EVENT `actualizar_estado_colaciones` ON SCHEDULE EVERY 1 DAY STARTS '2024-11-23 11:55:48' ON COMPLETION NOT PRESERVE ENABLE DO BEGIN
    -- Actualizar el estado de las colaciones a 'PASADO' si la fecha actual es mayor que la fecha de colación
    UPDATE colacion
    SET estado = 'PASADO'
    WHERE fecha_colación < CURDATE() AND estado != 'PASADO';
END$$

CREATE EVENT `actualizar_estado_colaciones_posgrado` ON SCHEDULE EVERY 1 DAY STARTS '2024-11-23 12:00:11' ON COMPLETION NOT PRESERVE ENABLE DO BEGIN
    -- Actualizar el estado de las colaciones a 'PASADO' si la fecha actual es mayor que la fecha de colación
    UPDATE colacion_posgrado
    SET estado = 'PASADO'
    WHERE fecha_colación < CURDATE() AND estado != 'PASADO';
END$$

